-- 90 CFB 27 Campus Legends (Superstar dev trait, ~88 OVR), sourced from the commissioner-supplied
-- college_legend_catalog_88ovr.xlsx roster (10 per position: QB/HB/FB/TE/WR/OL/DL/LB/DB).
-- game_scope='cfb_27' keeps these separate from the Madden legend catalog even where names collide
-- (e.g. Ray Lewis, Deion Sanders, Reggie White appear in both eras).

on conflict (name, position, game_scope) do update set
  position_group = excluded.position_group, est_ovr = excluded.est_ovr, height = excluded.height,
  weight = excluded.weight, hand = excluded.hand, jersey_number = excluded.jersey_number,
  dev_trait = excluded.dev_trait, archetype = excluded.archetype, build_note = excluded.build_note,
  college = excluded.college, attributes = excluded.attributes;
